	('0057', 'Điện thoại Nokia X20', '2.590.000', 20, 'Nokia X20 gây ấn tượng với dạng thiết kế theo xu hướng hiện đại ngày nay, điều này là để phù hợp hơn với giới trẻ và tự tin tỏa sáng khi cầm sản phẩm trên tay. Vật liệu kính ở mặt lưng cho phép hài hòa với ánh sáng và tạo nên hiệu ứng bắt mắt và thu hút.', 'nokia82-xanh.webp', NULL, '007', '057'),
	('0058', 'Điện thoại Nokia 110 4G Pro', '999.999', 15, 'Nokia 110 4G Pro đặc biệt thu hút người dùng với tạo hình nhỏ gọn, bền bỉ cùng tấm nền hiển thị LCD hiện đại cho trải nghiệm hình ảnh cực rõ nét. Nhờ được tích hợp chipset tân tiến, mọi thao tác nghe gọi, quay phim chụp hình của bạn trên Nokia 110 Pro luôn đảm bảo mượt mà, ổn định. Chưa hết, máy cũng sở hữu bộ nhớ trong, đáp ứng được mọi nhu cầu lưu trữ liên hệ của người sử dụng.', 'nokia110-den.webp', NULL, '007', '058'),
