INSERT INTO `productreview` (`reviewID`, `userID`, `productID`, `rating`, `comment`, `createAt`) VALUES
	('0001', '1733048839425', '0001', 4, 'Giao hàng siêu đúng hẹn, hàng cũng được đóng gói cẩn thận. Hiện tại mình xài được vài bữa thì không bị vấn đề gì. Hàng của shopdunk thì không lo về chất lượng.', NULL),
	('0002', '1733048839425', '0001', 3, 'Mặc dù vận chuyển lâu do lỗi, nhưng shop vẫn hỗ trợ mình rất nhiệt tình', NULL),
	('0003', '1733048839425', '0001', 5, 'Sản phẩm rất tốt vì là lần đầu tôi mua trên mạng đt nên thấy khá là lo lắng nhưng khi nhận đc hàng thì tôi lại thấy tốt hơn mong đợi của mình chúc Shop làm ăn mua may bán đắt', NULL),
	('0004', '1733048839425', '0001', 2, 'sản phầm tốt dễ dùng . Giao nhanh', NULL),
	('0005', '1733048839425', '0001', 1, 'giao hàng lâu. sản phẩm không như ý', NULL),
	('0006', '1733048839425', '0001', 5, 'sản phẩm tốt giá rẻ ưu đãi cho người dùng', NULL),
